import React from 'react';
import { useNavigate } from 'react-router-dom';

const Landing = () => {
  const navigate = useNavigate();
  return (
    <div className="landing-hero">
      <div className="landing-overlay" />
      <div className="landing-content">
        <h1 className="landing-title">GROW FINANCE</h1>
        <p className="landing-sub">Simplify billing, invoices and vendor management. Grow your business faster.</p>
        <div className="landing-actions">
          <button className="btn-primary" onClick={() => navigate('/signup')}>Get Started</button>
          <button className="btn-outline" onClick={() => navigate('/login')} style={{ marginLeft: 12 }}>Sign In</button>
        </div>
      </div>
    </div>
  );
};

export default Landing;
